const alerts = $input.first().json.alerts || [];
const alert = alerts[0] || {};
const labels = alert.labels || {};
const alertname = labels.alertname || 'unknown';
const endsAt = alert.endsAt || new Date().toISOString();
const msg = `**Resolved:** ${alertname}\n**Ended at:** ${endsAt}`;
return [{ json: { discord_message: msg, alertname, endsAt } }];

const payload = $input.first().json;
const prompt = `Alertmanager webhook received. Triage this alert.\n\n${JSON.stringify(payload, null, 2)}`;
return [{ json: { prompt } }];

const raw = $input.first().json.output || $input.first().json.text || '{}';
  const str = typeof raw === 'string' ? raw : JSON.stringify(raw);
  let result;
  try {
    result = JSON.parse(str);
  } catch (e) {
    // Try to extract JSON object from surrounding text
    const match = str.match(/\{[\s\S]*\}/);
    if (match) {
      try {
        result = JSON.parse(match[0]);
      } catch (e2) {
        result = null;
      }
    }
    if (!result) {
      result = {
        alert_message_id: null,
        alertname: 'parse_error',
        severity: 'warning',
        status: 'firing',
        skip: false,
        maintenance_context: null,
        summary: 'Failed to parse Claude Code output',
        findings: [`Raw output: ${str.substring(0, 500)}`],
        probable_cause: 'Claude Code returned non-JSON output',
        recommended_action: 'Check agent prompt and MCP connectivity',
        confidence: 'low',
        create_issue: false,
        github_issue_url: null,
        thread_name: `parse-error triage \u2014 ${new Date().toISOString().substring(11, 16)} UTC`
      };
    }
  }
  return [{ json: result }];

const d = $input.first().json;
let msg = '';
if (d.maintenance_context) {
  msg += `**Context:**\n- ${d.maintenance_context}\n\n`;
}
msg += `**What fired:**\n- ${d.summary}\n\n`;
msg += `**Investigation:**\n`;
(d.findings || []).forEach(f => { msg += `- ${f}\n`; });
msg += `\n**Probable cause:**\n${d.probable_cause}\n\n`;
msg += `**Recommended action:**\n${d.recommended_action}\n\n`;
msg += `**Confidence:** ${d.confidence}`;
const MAX = 1950;
const messages = [];
let current = '';
for (const line of msg.split('\n')) {
  if (current.length + line.length + 1 > MAX && current.length > 0) {
    messages.push(current.trimEnd());
    current = '';
  }
  current += line + '\n';
}
if (current.trim()) {
  messages.push(current.trimEnd());
}
return messages.map(m => ({ json: { ...d, discord_message: m } }));
